import java.io.IOException;

public class CommandInjectionFixed {

    public static void main(String[] args) throws IOException {
        String userInput = "example.txt";

        // Secure code using ProcessBuilder to prevent command injection
        ProcessBuilder processBuilder = new ProcessBuilder("cat", userInput);
        processBuilder.inheritIO(); // Redirects standard output and error to current process

        Process process = processBuilder.start();
        int exitCode = process.waitFor();

        if (exitCode == 0) {
            System.out.println("Command executed successfully.");
        } else {
            System.err.println("Error executing command.");
        }
    }
}

